const headers = $input.first().json.headers || {};
const provided = String(headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();
const expected = String($env.WEBHOOK_SECRET || '').trim();
const authorized = expected.length > 0 && provided === expected;
const body = $input.first().json.body ?? $input.first().json;
return [{ json: { authorized, body } }];

const body = $input.first().json.body || {};
const name = String(body.name || '').trim();
const email = String(body.email || '').trim().toLowerCase();
const company = String(body.company || '').trim();
const company_size = parseInt(body.company_size, 10) || 0;
const message = String(body.message || '').trim();
const source = String(body.source || 'webhook').trim();
const external_id = body.external_id || null;
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const valid = name && email && emailRe.test(email) && company_size >= 0;
const crypto = require('crypto');
const input_hash = valid ? crypto.createHash('sha256').update(`${email}|${name}|${message}`).digest('hex') : null;
return [{ json: { valid, name, email, company, company_size, message, source, external_id, input_hash } }];
